81:   Clear();
82:   len = aOther.len;
83:   if (!len) {
84:     ptr = (T*)alignof(T);
85:   } else {
86:     ptr = (T*)malloc(len * sizeof(T));
87:     size_t i = 0;
88:     for (const T& elem : aOther.AsSpan()) {
89:       new (ptr + i++) T(elem);
90:     }
91:   }
92: }
